import{_ as i,o as d,c as o,a2 as s}from"./chunks/framework.BZO4qERu.js";const p=JSON.parse('{"title":"目标：建立以会话和绑定为核心的本地后端体系","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/backend-status.md","filePath":"architecture/backend-status.md","lastUpdated":1780482865000}'),a={name:"architecture/backend-status.md"};function l(t,e,c,n,r,h){return d(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="目标-建立以会话和绑定为核心的本地后端体系" tabindex="-1">目标：建立以会话和绑定为核心的本地后端体系 <a class="header-anchor" href="#目标-建立以会话和绑定为核心的本地后端体系" aria-label="Permalink to &quot;目标：建立以会话和绑定为核心的本地后端体系&quot;">​</a></h1><p>目标：把 Codex-to-IM 的业务数据结构整理成一个清晰的本地后端体系。核心不是 SQLite/JSON 的技术选型，而是先把 <code>BridgeSession</code>、<code>ChannelChat</code>、线程身份、历史读取、mirror/reuse 等业务概念拆清楚。项目不引入真正的远端后端服务；自有小数据继续优先使用 JSON/JSONL，以保持可读、可调试、容易手工修复。</p><h2 id="当前结论" tabindex="-1">当前结论 <a class="header-anchor" href="#当前结论" aria-label="Permalink to &quot;当前结论&quot;">​</a></h2><ul><li>Codex-to-IM 自己的核心运行数据当前已经主要使用 JSON 文件存储。</li><li>SQLite 的使用点很集中，只在本地 Codex session 列表兼容逻辑中只读访问 <code>~/.codex/state_*.sqlite</code>。</li><li>后续改造重点不是“把项目从 SQLite 迁走”，也不是先抽通用 storage helper，而是先重构业务模型：<code>BridgeSession</code> 负责本地会话和唯一 Codex thread 身份，<code>ChannelChat</code> 只负责 IM 聊天到本地 session 的绑定。</li><li><code>codex_thread_id</code> 保留，并作为唯一的 Codex thread id 字段使用；不新增 <code>thread_id</code>。</li><li>旧字段 <code>sdk_session_id</code>、<code>desktop_thread_id</code>、<code>thread_origin</code>、旧 binding 的运行时字段要从业务模型中删除，不再作为 fallback 或兼容兜底。</li></ul><h2 id="业务模型目标" tabindex="-1">业务模型目标 <a class="header-anchor" href="#业务模型目标" aria-label="Permalink to &quot;业务模型目标&quot;">​</a></h2><h3 id="bridgesession" tabindex="-1">BridgeSession <a class="header-anchor" href="#bridgesession" aria-label="Permalink to &quot;BridgeSession&quot;">​</a></h3><p><code>BridgeSession</code> 是本地会话容器，负责承载一次可持续对话的业务状态。</p><p>保留职责：</p><ul><li>本地 session id。</li><li>会话名、工作目录、模型、默认模式、reasoning 设置。</li><li>运行态：running/queued/idle、health、mirror 状态、stream UI 状态。</li><li>消息缓存：<code>messages/&lt;sessionId&gt;.json</code>。</li><li>唯一 Codex thread 身份：<code>codex_thread_id</code>。</li></ul><p>字段收敛：</p><ul><li>保留 <code>codex_thread_id</code>：表示该 session 关联的 Codex thread id。</li><li>删除 <code>sdk_session_id</code>：不再把 SDK resume id 作为单独业务字段。</li><li>删除 <code>desktop_thread_id</code>：不再把 Native/Native 客户端作为业务核心身份。</li><li>删除 <code>thread_origin</code>：不再用 origin 字段决定业务路径。</li></ul><p>语义规则：</p><ul><li>没有 <code>codex_thread_id</code>：这是一个尚未创建 Codex thread 的本地 session。</li><li>有 <code>codex_thread_id</code>：这是一个已经关联 Codex thread 的本地 session。</li><li>这个 thread 可能来自普通 IM 对话，也可能来自用户接管已有 Codex 会话；业务逻辑不应再通过 <code>desktop_*</code> 字段区分。</li></ul><h3 id="channelchat" tabindex="-1">ChannelChat <a class="header-anchor" href="#channelchat" aria-label="Permalink to &quot;ChannelChat&quot;">​</a></h3><p><code>ChannelChat</code> 只表示“某个 IM chat 当前绑定到哪个本地 session”。</p><p>保留职责：</p><ul><li>channel instance：<code>channelType</code>、<code>channelProvider</code>、<code>channelAlias</code>。</li><li>chat 身份：<code>chatId</code>、<code>chatKind</code>、<code>chatUserId</code>。</li><li>本地 session 指针：<code>bridgeSessionId</code>。</li></ul><p>字段收敛：</p><ul><li>删除旧 <code>active</code> 状态；一个 IM chat 只有一个 ChannelChat，一个 BridgeSession 也只保留一个聊天绑定。</li><li>删除旧 <code>workingDirectory</code>、<code>model</code>、<code>mode</code>、<code>chatDisplayName</code>；这些运行时和展示字段归属 <code>BridgeSession</code>。</li><li>ChannelChat 不再缓存 Codex thread id。</li><li>ChannelChat 不再参与 thread 身份判断。</li><li>所有 thread id 读取都必须从 <code>store.getSession(channelChat.bridgeSessionId)?.codex_thread_id</code> 获取。</li></ul><h3 id="线程相关能力" tabindex="-1">线程相关能力 <a class="header-anchor" href="#线程相关能力" aria-label="Permalink to &quot;线程相关能力&quot;">​</a></h3><p>以下能力都基于 <code>BridgeSession.codex_thread_id</code>：</p><ul><li>普通 IM 对话 resume。</li><li><code>/t</code> 选择或接管已有 Codex 会话。</li><li>history 读取。</li><li>mirror 订阅。</li><li>reuse 当前 Codex thread。</li><li>tmux provider resume。</li></ul><p>不再允许以下 fallback：</p><ul><li>从旧 binding 的 <code>sdkSessionId</code> 读 thread id。</li><li>从 <code>BridgeSession.sdk_session_id</code> 读 thread id。</li><li>从 <code>BridgeSession.desktop_thread_id</code> 读 thread id。</li><li>通过 <code>thread_origin === &#39;desktop&#39;</code> 决定 mirror/reuse。</li></ul><h3 id="命名原则" tabindex="-1">命名原则 <a class="header-anchor" href="#命名原则" aria-label="Permalink to &quot;命名原则&quot;">​</a></h3><ul><li>用户界面可以继续出现“本地 Codex 会话”这类用户能理解的入口描述。</li><li>内部业务模型不再把 Native/Native 客户端作为核心抽象。</li><li>代码里的新逻辑应围绕 <code>codex_thread_id</code>、session、ChannelChat 命名。</li><li>旧函数名如 <code>bindStoreToSdkSession</code> 应改成更准确的“绑定到 Codex thread”语义。</li></ul><h2 id="当前-json-存储" tabindex="-1">当前 JSON 存储 <a class="header-anchor" href="#当前-json-存储" aria-label="Permalink to &quot;当前 JSON 存储&quot;">​</a></h2><p><code>src/storage/json-store.ts</code> 中的 <code>JsonFileStore</code> 是当前 Bridge 运行期数据的主存储实现，数据目录位于 <code>CTI_HOME/data</code>。</p><p>主要文件包括：</p><ul><li><code>sessions.json</code>：Bridge session 记录。</li><li><code>channel-chats.json</code>：IM channel chat 与 session 的绑定关系。</li><li><code>channel-default-targets.json</code>：通道默认目标。</li><li><code>permissions.json</code>：权限回调链接。</li><li><code>offsets.json</code>：消费偏移量。</li><li><code>dedup.json</code>：去重键。</li><li><code>audit.json</code>：审计日志。</li><li><code>messages/&lt;sessionId&gt;.json</code>：单个 Bridge session 的消息缓存。</li></ul><p>其它模块也有独立 JSON 状态文件：</p><ul><li><code>config.v2.json</code>：结构化配置文件。</li><li><code>ui-session-meta.json</code>：旧 UI session 名称元数据；启动迁移会合并进 <code>sessions.json.name</code> 并删除该文件。</li><li><code>thread-table-messages.json</code>：线程表格消息置顶/展示记录。</li><li><code>runtime/status.json</code>、<code>runtime/ui-server.json</code>：服务运行状态。</li></ul><h2 id="存储边界" tabindex="-1">存储边界 <a class="header-anchor" href="#存储边界" aria-label="Permalink to &quot;存储边界&quot;">​</a></h2><p>Codex-to-IM 自有数据：</p><ul><li>使用 JSON/JSONL。</li><li>支持人工检查和修复。</li><li>先保证业务字段清晰，再考虑统一 storage helper。</li><li>后续可以增加 schema version、迁移、备份和损坏恢复策略。</li></ul><p>Codex 外部数据：</p><ul><li>Codex Native session JSONL：只读解析。</li><li>Codex Native <code>state_*.sqlite</code>：只读兼容读取。</li><li>Codex CLI/SDK thread id：写入本地 session 的 <code>codex_thread_id</code>，不再写入 ChannelChat。</li></ul><h3 id="_5-api-层" tabindex="-1">5. API 层 <a class="header-anchor" href="#_5-api-层" aria-label="Permalink to &quot;5. API 层&quot;">​</a></h3><p>目标：让 UI server 和 IM 命令共享更清晰的本地后端契约。</p><p>计划：</p><ul><li>为 UI server 的本地接口定义 typed request/response。</li><li>修改类接口增加输入校验。</li><li>错误返回统一为：</li></ul><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;ok&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ERROR_CODE&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;message&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Human readable message&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li>UI 只依赖 API DTO，不直接理解存储文件结构。</li></ul><h3 id="_6-runtime-层" tabindex="-1">6. Runtime 层 <a class="header-anchor" href="#_6-runtime-层" aria-label="Permalink to &quot;6. Runtime 层&quot;">​</a></h3><p>目标：统一 bridge、UI server、mirror、health 和 hot update 的状态表达。</p><p>计划：</p><ul><li>梳理 <code>runtime/status.json</code>、<code>runtime/ui-server.json</code> 等状态文件。</li><li>统一字段：<code>running</code>、<code>pid</code>、<code>port</code>、<code>startedAt</code>、<code>lastError</code>、<code>updatedAt</code>。</li><li>doctor 脚本读取 runtime 状态、配置文件和日志，输出可执行的修复建议。</li><li>状态查询保持只读，不承担运行态修复动作。</li></ul><h2 id="测试计划" tabindex="-1">测试计划 <a class="header-anchor" href="#测试计划" aria-label="Permalink to &quot;测试计划&quot;">​</a></h2><ul><li>Store：<code>codex_thread_id</code> 只写 session，不写 ChannelChat。</li><li>ChannelChat：删除旧运行时字段后仍能创建、切换、删除、列出。</li><li>Conflict：同一个 session 或同一个 chat 只能保留一个 ChannelChat。</li><li><code>/t</code>：接管已有 Codex 会话会写 session 的 <code>codex_thread_id</code>。</li><li>History：优先用 session 的 <code>codex_thread_id</code> 查外部 JSONL，找不到退回 Bridge messages。</li><li>Mirror：只根据 session 的 <code>codex_thread_id</code> 建立订阅。</li><li>Reuse：普通 IM 对话只根据 session 的 <code>codex_thread_id</code> resume。</li><li>Tmux：只根据 session 的 <code>codex_thread_id</code> resume。</li><li>Full：typecheck、全量 test、build 通过后再热更新。</li></ul><h2 id="交付顺序" tabindex="-1">交付顺序 <a class="header-anchor" href="#交付顺序" aria-label="Permalink to &quot;交付顺序&quot;">​</a></h2><ol><li>更新业务模型文档，明确 <code>codex_thread_id</code> 是唯一 thread id。</li><li>修改类型定义：删除 session 和旧 binding 上的旧 thread 字段。</li><li>修改 store 接口和实现：thread id 只写 session。</li><li>修改 ChannelChat/session helper：不再读写旧 <code>binding.sdkSessionId</code>。</li><li>修改 <code>/t</code>、history、mirror、reuse、tmux provider 的 thread id 来源。</li><li>更新测试，删除旧字段断言，补新业务结构断言。</li><li>跑 <code>nvm use 24</code> 后执行 typecheck、test、build。</li><li>验证通过后热更新 bridge；不 commit、不 push。</li></ol><h2 id="非目标" tabindex="-1">非目标 <a class="header-anchor" href="#非目标" aria-label="Permalink to &quot;非目标&quot;">​</a></h2><ul><li>不引入远端数据库。</li><li>不把项目自有小数据迁移到 SQLite。</li><li>不改变 Codex Native 自己的数据格式。</li><li>不重写飞书 adapter 的底层 API。</li><li>不新增 <code>thread_id</code> 字段替代 <code>codex_thread_id</code>。</li><li>不保留旧字段作为 fallback。</li><li>不在验证通过前热更新本机 bridge。</li></ul>`,53)])])}const k=i(a,[["render",l]]);export{p as __pageData,k as default};
